; ============================================================================
; BG Palettes — Palettes 0-6 from converted image, palette 7 for menu text
; (Palette data is small, stays in bank 0)
; ============================================================================

title_img_palette:
.INCBIN "gfx/converted/title.pal"
title_img_palette_end:

; Palette 7: menu text (white on transparent)
title_menu_palette:
.dw $0000    ; 0: transparent
.dw $7FFF    ; 1: white
.dw $0000, $0000, $0000, $0000, $0000, $0000
.dw $0000, $0000, $0000, $0000
.dw $0000, $0000, $0000, $0000
title_menu_palette_end:


; ============================================================================
; Large image data placed in bank 1 to avoid overflowing bank 0.
; DMA source bank is set via :label which returns the ROM bank byte.
; ============================================================================
.BANK 1 SLOT 0
.ORG $0000

; BG2 Converted Image Tiles (4bpp, generated by img2snes.py)
title_img_tiles:
.INCBIN "gfx/converted/title.tiles"
title_img_tiles_end:

; BG2 Converted Tilemap (32x28, generated by img2snes.py)
title_img_map:
.INCBIN "gfx/converted/title.map"
title_img_map_end:

; Return to bank 0 for subsequent includes
.BANK 0 SLOT 0


